  "name": "filebrowser-ui",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "test": "vitest run",
    "watch": "tsc --watch"
  },
