  const path = normalizeRelativePath(getCurrentRoute().path);
  for (const file of files) {
    await api.upload(path, file);
  }
  // Clear the input so selecting the same file again re-fires `change`.
  // The DOM `files` property is readonly; assigning an empty DataTransfer
  // resets it in standards-compliant browsers / happy-dom.
  clearFileInput(/* ref to uploadInput */);
  render();
}

