function renderBreadcrumb(path: string): void {
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  // Home / root link
  const homeLink = document.createElement('a');
  homeLink.href = toBrowseHash('');
  homeLink.textContent = 'Home';
  breadcrumbEl.append(homeLink);

  let cumulative = '';
  for (const seg of segments) {
    cumulative = joinPath(cumulative, seg);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator);
    const link = document.createElement('a');
    link.href = toBrowseHash(cumulative);
    link.textContent = seg;
    breadcrumbEl.append(link);
  }
}
