function makeBrowseEntryRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name cell
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    const link = document.createElement('a');
    link.href = toBrowseHash(entry.path);
    link.textContent = entry.name;
    nameCell.append(link);
  } else {
    nameCell.textContent = entry.name;
  }

  // Size cell
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified cell
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions cell
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const downloadLink = document.createElement('a');
    downloadLink.className = 'btn';
    downloadLink.href = api.downloadUrl(entry.path);
    downloadLink.setAttribute('download', entry.name);
    downloadLink.textContent = 'Download';
    actionsCell.append(downloadLink);
  }
  actionsCell.append(makeDeleteButton(entry));
  actionsCell.append(makeMoveButton(entry));
  actionsCell.append(makeCopyButton(entry));

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}
```

