```typescript
/**
 * SPA entry: ties together `api`, `router`, and the DOM.
 *
 * Renders a file-browser UI inside a native `<dialog>` widget. A trigger
 * button opens the dialog; inside it, a toolbar (breadcrumb, search, upload)
 * sits above a results table and a status footer. All file operations
 * (browse, search, upload, download, delete, move, copy) are wired here.
 */
import { ApiClient } from './api.js';
import type { BrowseResult, FileEntry, SearchResult } from './api.js';
import { parseHash, getCurrentRoute, subscribe, toBrowseHash, toSearchHash, navigate } from './router.js';
import type { Route } from './router.js';
import { formatBytes, normalizeRelativePath, joinPath, parentPath, basename, formatDate } from './format.js';

const api = new ApiClient();

/* -------------------------------------------------------------------------
 * Module-level DOM references
 *
 * `startApp` populates these; `render`, `renderBrowse`, and `renderSearch`
 * (the latter two are exported for direct unit testing) read and mutate them.
 * Every test re-runs `startApp` against a fresh container, so these always
 * point at the currently-mounted app's elements.
 * ---------------------------------------------------------------------- */
let resultsEl!: HTMLElement;
let statusEl!: HTMLElement;
let breadcrumbEl!: HTMLElement;
let searchInput!: HTMLInputElement;
let uploadInput!: HTMLInputElement;

/* =========================================================================
 * startApp — build the DOM, wire events, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Dialog --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Header: title span + Close button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const title = document.createElement('span');
  title.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'btn';
  closeBtn.textContent = 'Close';
  header.append(title, closeBtn);

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.hidden = true;
  uploadInput.multiple = true;
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  statusEl = document.createElement('footer');
  statusEl.className = 'status';

  dialog.append(header, toolbar, resultsEl, statusEl);
  root.append(trigger, dialog);

  /* --- Event wiring --- */
  trigger.addEventListener('click', () => dialog.showModal());
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Route subscription + initial render --- */
  subscribe(render);
  render();
}

/* =========================================================================
 * Toolbar handlers
 * ========================================================================= */

/** Navigate to a search hash built from the input value and current path. */
function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  navigate(toSearchHash(searchInput.value.trim(), path));
}

/** Upload every selected file to the current path, clear the input, re-render. */
async function handleUpload(): Promise<void> {
  const fileList = uploadInput.files;
  const files = fileList ? Array.from(fileList) : [];
  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(getCurrentRoute().path);
  for (const file of files) {
    await api.upload(path, file);
  }
  uploadInput.value = '';
  render();
}

/* =========================================================================
 * render — orchestrates API call + delegation based on the current route
 * ========================================================================= */

async function render(): Promise<void> {
  const route = getCurrentRoute();

  // Clear previous output before rendering the new route.
  resultsEl.innerHTML = '';
  breadcrumbEl.innerHTML = '';
  statusEl.textContent = '';

  try {
    if (route.view === 'browse') {
      const result = await api.browse(normalizeRelativePath(route.path));
      renderBrowse(result, route);
    } else {
      const result = await api.search(route.query, normalizeRelativePath(route.path));
      renderSearch(result, route);
    }
  } catch (err) {
    resultsEl.textContent = err instanceof Error
      ? 'Error: ' + err.message
      : 'Error: ' + String(err);
  }
}

/* =========================================================================
 * renderBrowse — table for a BrowseResult
 * ========================================================================= */

export function renderBrowse(result: BrowseResult, _route: Route): void {
  renderBreadcrumb(result.path);
  statusEl.textContent =
    result.folderCount + ' folders, ' +
    result.fileCount + ' files, total ' +
    formatBytes(result.totalSize);

  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/* =========================================================================
 * renderSearch — table for a SearchResult
 * ========================================================================= */

export function renderSearch(result: SearchResult, _route: Route): void {
  renderBreadcrumb(result.path);
  statusEl.textContent = result.results.length + ' results for "' + result.query + '"';

  const table = buildTable(['Name', 'Path', 'Size', 'Modified']);
  const tbody = table.querySelector('tbody')!;

  for (const entry of result.results) {
    tbody.append(makeSearchRow(entry));
  }

  resultsEl.append(table);
}

/* =========================================================================
 * DOM-builder helpers
 * ========================================================================= */

/**
 * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
 * `<tbody>`. Caller appends rows to the `<tbody>`.
 */
function buildTable(headers: string[]): HTMLTableElement {
  const table = document.createElement('table');
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  for (const label of headers) {
    const th = document.createElement('th');
    th.textContent = label;
    headRow.append(th);
  }
  thead.append(headRow);
  const tbody = document.createElement('tbody');
  table.append(thead, tbody);
  return table;
}

/**
 * Render clickable breadcrumb segments into `breadcrumbEl`. Each segment
 * navigates to its cumulative path; a leading "Home" segment navigates to root.
 */
function renderBreadcrumb(path: string): void {
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  breadcrumbEl.append(makeBreadcrumbLink('Home', ''));

  let cumulative = '';
  for (const segment of segments) {
    cumulative = joinPath(cumulative, segment);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator, makeBreadcrumbLink(segment, cumulative));
  }
}

/** A breadcrumb `<a>` that navigates to `toBrowseHash(path)` on click. */
function makeBreadcrumbLink(text: string, path: string): HTMLAnchorElement {
  return makeNavLink(text, toBrowseHash(path));
}

/**
 * Build an `<a>` whose click calls `navigate(hash)` (with `preventDefault` so
 * the browser does not also follow the href). The href is still set for
 * accessibility, middle-click, and copy-link support.
 */
function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.href = hash;
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** A browse-view data row for a single file or folder entry. */
function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.href = api.downloadUrl(entry.path);
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    actionsCell.append(download);
  }
  actionsCell.append(
    makeDeleteButton(entry),
    makeMoveButton(entry),
    makeCopyButton(entry),
  );

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** Delete button: confirm, then call `api.delete` and re-render. */
function makeDeleteButton(entry: FileEntry): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = 'Delete';
  btn.addEventListener('click', async () => {
    if (!window.confirm('Delete "' + entry.name + '"?')) {
      return;
    }
    await api.delete(entry.path);
    render();
  });
  return btn;
}

/** Move button: prompt for a destination, then call `api.move` and re-render. */
function makeMoveButton(entry: FileEntry): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = 'Move';
  btn.addEventListener('click', async () => {
    const destination = window.prompt('Move to relative destination path:', entry.path);
    if (destination === null) {
      return;
    }
    await api.move(entry.path, normalizeRelativePath(destination));
    render();
  });
  return btn;
}

/** Copy button: prompt for a destination, then call `api.copy` and re-render. */
function makeCopyButton(entry: FileEntry): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = 'Copy';
  btn.addEventListener('click', async () => {
    const destination = window.prompt('Copy to relative destination path:', entry.path);
    if (destination === null) {
      return;
    }
    await api.copy(entry.path, normalizeRelativePath(destination));
    render();
  });
  return btn;
}

/** A search-view data row. Directory names browse; file names download. */
function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.href = api.downloadUrl(entry.path);
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

/* =========================================================================
 * Bootstrap (guarded so the module is importable in tests without a DOM)
 * ========================================================================= */

const root = document.getElementById('app');
if (root) {
  startApp(root);
}
```

