export class ApiClient {
    baseUrl;
    constructor(baseUrl = '/api/files') {
        this.baseUrl = baseUrl;
    }
    async browse(path) {
        return this.request(`${this.baseUrl}/browse?path=${encodeURIComponent(path)}`, { method: 'GET' });
    }
    async search(query, path) {
        return this.request(`${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`, { method: 'GET' });
    }
    async upload(path, file) {
        const formData = new FormData();
        formData.append('file', file);
        return this.request(`${this.baseUrl}/upload?path=${encodeURIComponent(path)}`, { method: 'POST', body: formData });
    }
    async delete(path) {
        await this.request(`${this.baseUrl}/delete?path=${encodeURIComponent(path)}`, { method: 'DELETE' });
    }
    async move(source, destination) {
        await this.request(`${this.baseUrl}/move`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
        });
    }
    async copy(source, destination) {
        await this.request(`${this.baseUrl}/copy`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
        });
    }
    downloadUrl(path) {
        return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
    }
    async request(url, init) {
        const res = await fetch(url, init);
        if (!res.ok) {
            throw new Error(res.status + ': ' + await res.text());
        }
        return await res.json();
    }
}
